[
  {
    "text": "The SplitMultisampleVcf workflow extracts all samples from a provided multi-sample VCF file.",
    "topic": "SplitMultisampleVcf workflow"
  },
  {
    "text": "The extracted samples are divided into chunks based on a specified chunk size.",
    "topic": "SplitMultisampleVcf workflow"
  },
  {
    "text": "A new sample list is generated for each chunk of samples.",
    "topic": "SplitMultisampleVcf workflow"
  },
  {
    "text": "The chunked sample list is used to extract corresponding samples from the original multi-sample VCF file.",
    "topic": "SplitMultisampleVcf workflow"
  },
  {
    "text": "The result is the creation of new single-sample VCF files for each chunk of samples.",
    "topic": "SplitMultisampleVcf workflow"
  }
]
